/* Node.js cache‑aside with Redis and Postgres (example for production use would add error handling, logging, and stampede protections) */

const { Pool } = require('pg')
const Redis = require('ioredis')

const pg = new Pool(/* config */)
const redis = new Redis(/* config */)

async function getUser(id) {
  const key = `user:${id}`
  const cached = await redis.get(key)
  if (cached) return JSON.parse(cached)

  // Acquire a lightweight lock to avoid stampede (simplified)
  const lockKey = `${key}:lock`
  const gotLock = await redis.set(lockKey, '1', 'NX', 'PX', 5000)
  if (!gotLock) {
    // wait briefly then retry cache
    await new Promise(r => setTimeout(r, 50))
    const retry = await redis.get(key)
    if (retry) return JSON.parse(retry)
  }

  const res = await pg.query('select * from users where id = $1', [id])
  const user = res.rows[0]
  if (user) await redis.set(key, JSON.stringify(user), 'EX', 300)
  await redis.del(lockKey)
  return user
}
